        if (reset) 
            Q <= 0;
        else if (T) 
            Q <= ~Q;
    end
  always @(*) begin
    if (1'b0) begin
      if (Q) begin
        Q <= 0;
      end else begin
        Q <= 1;
      end;
    end
  end

endmodule

